import numpy as np

def compute_kl_penalty(log_p_actor, log_p_ref, beta=0.1):
    return beta * (log_p_actor - log_p_ref)

def run_practice():
    pen = compute_kl_penalty(np.log(0.5), np.log(0.25), 0.1)
    assert np.allclose(pen, 0.0693147)
    print('[PASS] KL penalty calculations verified.')

if __name__ == '__main__':
    run_practice()
